#!/usr/bin/env bash
# SPDX-License-Identifier: MIT
# Copyright (c) 2025-2026 Kaptain contributors (Fred Cooke)
#
# postVersionsAndNaming hook: pulls the pinned vendor-envoy-gateway release
# (full version in src/upstream/version) and unpacks its manifests zip
# under ${OUTPUT_SUB_PATH}/vendor-envoy-gateway/. Then regenerates
# src/kubernetes/role-infra-manager.yaml and
# src/kubernetes/rolebinding-infra-manager.yaml from the pulled upstream
# manifests, swapping upstream identity labels for ours and pointing the
# rolebinding subject at ${RunPlatform}. Fails if those regenerated files
# differ from what's committed in src/kubernetes/.
#
set -euo pipefail

read -r full_tag < src/upstream/version

OWNER="kube-kaptain"
REPO="vendor-envoy-gateway"

asset_name="${REPO}-${full_tag}-manifests.zip"
asset_url="https://github.com/${OWNER}/${REPO}/releases/download/${full_tag}/${asset_name}"

target_dir="${OUTPUT_SUB_PATH}/vendor-envoy-gateway"
mkdir -p "${target_dir}"

echo "Pulling ${asset_name} from ${asset_url}..."
curl -fsSL "${asset_url}" -o "${target_dir}/${asset_name}"
unzip -q "${target_dir}/${asset_name}" -d "${target_dir}"
echo "Extracted ${asset_name} to ${target_dir}"

extracted_dir="${target_dir}/vendor-envoy-gateway"
modified_dir="${target_dir}/modified"
dest_dir="src/kubernetes"

mkdir -p "${modified_dir}"

# Wipe upstream's labels/annotations and inject the canonical kaptain set with
# proxy-side tokens. The upstream package was built with whatever tooling it
# was at the time, so we don't rely on it carrying our current label set.
export UPSTREAM_SOURCE="kube-kaptain/vendor-envoy-gateway:${full_tag}"

inject_canonical_metadata() {
  local input="$1"
  local output="$2"
  cp "${input}" "${output}"
  yq eval -i '
    .metadata.labels = {} |
    .metadata.annotations = {} |
    .metadata.labels.app = .metadata.name |
    .metadata.labels."app.kubernetes.io/name" = .metadata.name |
    .metadata.labels."app.kubernetes.io/version" = "${Version}" |
    .metadata.labels."app.kubernetes.io/version" style = "double" |
    .metadata.labels."app.kubernetes.io/managed-by" = "Kaptain" |
    .metadata.labels."app.kubernetes.io/part-of" = "${ProductName}" |
    .metadata.labels."kaptain.org/environment" = "${Environment}" |
    .metadata.labels."kaptain.org/product" = "${ProductName}" |
    .metadata.labels."kaptain.org/project-name" = "${ProjectName}" |
    .metadata.labels."kaptain.org/version" = "${Version}" |
    .metadata.labels."kaptain.org/version" style = "double" |
    .metadata.labels."kaptain.org/owner" = "kube-kaptain" |
    .metadata.annotations."kaptain.org/upstream-source" = strenv(UPSTREAM_SOURCE) |
    .metadata.annotations."kaptain.org/source-repository" = "kube-kaptain/vendor-envoy-gateway-proxy" |
    .metadata.annotations."kaptain.org/generated-by" = "Generated by .github/bin/pull-vendor-envoy-gateway.bash" |
    .metadata = (.metadata | pick(["name", "namespace", "labels", "annotations"]))
  ' "${output}"
}

inject_canonical_metadata "${extracted_dir}/role-infra-manager.yaml" \
  "${modified_dir}/role-infra-manager.yaml"

inject_canonical_metadata "${extracted_dir}/rolebinding-infra-manager.yaml" \
  "${modified_dir}/rolebinding-infra-manager.yaml"

# Rolebinding subjects live in the gateway controller's namespace (RunPlatform),
# not the proxy's environment namespace.
yq eval -i '.subjects[].namespace = "${RunPlatform}"' \
  "${modified_dir}/rolebinding-infra-manager.yaml"

cp "${modified_dir}/role-infra-manager.yaml" "${dest_dir}/role-infra-manager.yaml"
cp "${modified_dir}/rolebinding-infra-manager.yaml" "${dest_dir}/rolebinding-infra-manager.yaml"

if ! git diff --quiet -- "${dest_dir}"; then
  echo "ERROR: ${dest_dir} drifted from upstream-derived expected output." >&2
  echo "Run this hook locally and commit the regenerated files." >&2
  git --no-pager diff -- "${dest_dir}" >&2
  exit 1
fi

echo "src/kubernetes/ matches upstream-derived expected output"
